import socket
import threading
from collections import defaultdict

# Constants
HOST = '127.0.0.1'
PORT = 65432
MAX_PLAYERS = 100

# Player data structure
Player = namedtuple('Player', ['id', 'position', 'view_range'])

# Game state
players = {}
player_connections = {}

# Server socket setup
server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
server_socket.bind((HOST, PORT))
server_socket.listen(MAX_PLAYERS)

def handle_client(client_socket):
    while True:
        try:
            data = client_socket.recv(1024).decode()
            if not data:
                break
            player_id, position_str = data.split(',')
            player_position = tuple(map(float, position_str.split()))
            players[player_id] = Player(player_id, player_position, 50.0)  # Example view range
            broadcast_game_state()
        except Exception as e:
            print(f"Error handling client: {e}")
            break
    client_socket.close()

def broadcast_game_state():
    for client_socket in player_connections.values():
        visible_players = [player for player in players.values() if is_visible(players[player.id], player_position)]
        data = ','.join([f"{player.id},{','.join(map(str, player.position))}" for player in visible_players])
        client_socket.sendall(data.encode())

def is_visible(player1, player2):
    # Simplified line of sight check
    return abs(player1.position[0] - player2.position[0]) < player1.view_range and \
           abs(player1.position[1] - player2.position[1]) < player1.view_range

print(f"Server listening on {HOST}:{PORT}")

while True:
    client_socket, addr = server_socket.accept()
    print(f"Accepted connection from {addr}")
    player_id = str(len(players) + 1)
    players[player_id] = Player(player_id, (0, 0), 50.0)  # Example initial position and view range
    player_connections[player_id] = client_socket
    client_thread = threading.Thread(target=handle_client, args=(client_socket,))
    client_thread.start()